\begin{corollary}\leanok
[Locally trivial \(\Rightarrow\) finite type]
  \label{cor:lbc_isFiniteType}
  \lean{AlgebraicGeometry.Scheme.LineBundle.IsLocallyTrivial.isFiniteType}
  \uses{thm:lbc_isFinitePresentation}
  Under the hypotheses of \cref{thm:lbc_isFinitePresentation}, the locally
  trivial module \(M\) is of finite type (\(M.\mathtt{IsFiniteType}\)). This is
  the named result. Quasi-coherence (\(M.\mathtt{IsQuasicoherent}\)) follows
  automatically and needs no separate named theorem: it is supplied by the
  Mathlib instance \(\mathtt{SheafOfModules.instIsQuasicoherentOfIsFinitePresentation}\)
  from \cref{thm:lbc_isFinitePresentation}.
\end{corollary}

\begin{proof}
  \uses{thm:lbc_isFinitePresentation}
  Finite presentation implies finite type by Mathlib's
  \(\mathtt{SheafOfModules.instIsFiniteTypeOfIsFinitePresentation}\), immediate
  from \cref{thm:lbc_isFinitePresentation}; this is the content of the named
  declaration. Quasi-coherence is not separately stated in the Lean type — it is
  available as the Mathlib instance
  \(\mathtt{SheafOfModules.instIsQuasicoherentOfIsFinitePresentation}\), again
  immediate from \cref{thm:lbc_isFinitePresentation}.
\end{proof}
